"use strict";(self.webpackChunkmagento2_hyva_jewellery_theme_docs=self.webpackChunkmagento2_hyva_jewellery_theme_docs||[]).push([[1219],{8828(t,o,e){e.r(o),e.d(o,{comp:()=>d,data:()=>a});var r=e(641);const s={},d=(0,e(6262).A)(s,[["render",function(t,o){return(0,r.uX)(),(0,r.CE)("div",null,[...o[0]||(o[0]=[(0,r.Fv)('<h1 id="product-carousel" tabindex="-1"><a class="header-anchor" href="#product-carousel"><span>Product Carousel</span></a></h1><p>The <strong>Product Carousel</strong> section shows products on the homepage. Use it for Trending Products, New Arrivals, Bestsellers, Sale items, or products from one category.</p><p>It can show as a slider or as a grid.</p><h2 id="add-a-product-carousel" tabindex="-1"><a class="header-anchor" href="#add-a-product-carousel"><span>Add a Product Carousel</span></a></h2><ol><li>Go to <strong>Content -&gt; Homepage Configurator -&gt; Sections</strong>.</li><li>Click <strong>Add New Section</strong>.</li><li>Enter a <strong>Title</strong>, for example <code>New Arrivals</code>.</li><li>Set <strong>Section Type</strong> to <strong>Product Carousel</strong>.</li><li>Set <strong>Enabled</strong> to <strong>Yes</strong>.</li><li>Use a <strong>Sort Order</strong> such as <code>30</code> or <code>40</code>.</li><li>Fill the <strong>Product Carousel Configuration</strong> fields.</li><li>Click <strong>Save</strong>.</li></ol><p><img src="/hyva-jewelry-theme/screenshots/product-carousel-edit-general.png" alt="Magento Admin Edit Section page for Product Carousel"></p><h2 id="product-source" tabindex="-1"><a class="header-anchor" href="#product-source"><span>Product source</span></a></h2><p>Choose how products should be selected.</p><table><thead><tr><th>Product Source</th><th>When to use it</th></tr></thead><tbody><tr><td><strong>New Products</strong></td><td>Show latest products from your catalog.</td></tr><tr><td><strong>Category</strong></td><td>Show products from one selected category.</td></tr><tr><td><strong>Manual SKUs</strong></td><td>Choose exact products yourself.</td></tr><tr><td><strong>Bestsellers</strong></td><td>Show products that sell well.</td></tr><tr><td><strong>On Sale</strong></td><td>Show discounted products.</td></tr></tbody></table><p><img src="/hyva-jewelry-theme/screenshots/product-carousel-source-settings.png" alt="Magento Admin Product Carousel source settings"></p><p>If you choose <strong>Category</strong>, also choose the category. If you choose <strong>Manual SKUs</strong>, select the products you want to show.</p><h2 id="display-settings" tabindex="-1"><a class="header-anchor" href="#display-settings"><span>Display settings</span></a></h2><table><thead><tr><th>Setting</th><th>What it does</th></tr></thead><tbody><tr><td><strong>Subtitle</strong></td><td>Small text under the section title.</td></tr><tr><td><strong>Display Mode</strong></td><td>Choose <strong>Slider View</strong> or <strong>Grid View</strong>.</td></tr><tr><td><strong>Number of Products to Show</strong></td><td>Choose how many products should show.</td></tr><tr><td><strong>Products per View Desktop</strong></td><td>Number of products visible at one time on desktop.</td></tr><tr><td><strong>Products per View Mobile</strong></td><td>Number of products visible at one time on mobile.</td></tr></tbody></table><p><img src="/hyva-jewelry-theme/screenshots/product-carousel-display-card-settings.png" alt="Magento Admin Product Carousel display and card settings"></p><h2 id="product-card-options" tabindex="-1"><a class="header-anchor" href="#product-card-options"><span>Product card options</span></a></h2><p>Use these switches to control what shoppers see on each product card.</p><table><thead><tr><th>Option</th><th>What it shows</th></tr></thead><tbody><tr><td><strong>Show Rating</strong></td><td>Product rating stars.</td></tr><tr><td><strong>Show Price</strong></td><td>Product price.</td></tr><tr><td><strong>Show Add to Cart</strong></td><td>Add to Cart button.</td></tr><tr><td><strong>Show Wishlist</strong></td><td>Wishlist button.</td></tr><tr><td><strong>Show Quick View</strong></td><td>Quick View button.</td></tr></tbody></table><h2 id="storefront-result" tabindex="-1"><a class="header-anchor" href="#storefront-result"><span>Storefront result</span></a></h2><p><img src="/hyva-jewelry-theme/screenshots/product-carousel-storefront-result.png" alt="Trending products carousel on the storefront"></p><h2 id="good-practice" tabindex="-1"><a class="header-anchor" href="#good-practice"><span>Good practice</span></a></h2><ul><li>Use 8 to 12 products for a clean slider.</li><li>Use short section titles, like <code>New Arrivals</code> or <code>Trending Products</code>.</li><li>Keep price and Add to Cart visible when the goal is quick shopping.</li><li>Use one carousel for each purpose instead of one very long section.</li></ul>',21)])])}]]),a=JSON.parse('{"path":"/hyva-jewelry-theme/homepage/product-carousel.html","title":"Product Carousel","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"Add a Product Carousel","slug":"add-a-product-carousel","link":"#add-a-product-carousel","children":[]},{"level":2,"title":"Product source","slug":"product-source","link":"#product-source","children":[]},{"level":2,"title":"Display settings","slug":"display-settings","link":"#display-settings","children":[]},{"level":2,"title":"Product card options","slug":"product-card-options","link":"#product-card-options","children":[]},{"level":2,"title":"Storefront result","slug":"storefront-result","link":"#storefront-result","children":[]},{"level":2,"title":"Good practice","slug":"good-practice","link":"#good-practice","children":[]}],"git":{"contributors":[{"name":"anikesh kumar","username":"","email":"anikesh.kumar204@webkul.in","commits":1}],"changelog":[{"hash":"65ee1538c72e98b02c838952f96993746b91fe68","time":1783608557000,"email":"anikesh.kumar204@webkul.in","author":"anikesh kumar","message":"init"}]},"filePathRelative":"homepage/product-carousel.md"}')}}]);